1	import { useQuery } from "@tanstack/react-query";
2	import type { Asset } from "@/types/assets";
3	import {
4	  ContextMenu,
5	  ContextMenuContent,
6	  ContextMenuItem,
7	  ContextMenuSeparator,
8	  ContextMenuTrigger,
9	} from "@/components/ui/context-menu";
10	import { Download, FolderOpen, Copy, PanelRight, Loader2, ImageOff } from "lucide-react";
11	import { cn } from "@/lib/utils";
12	import { supabase } from "@/integrations/supabase/client";
13	import { buildOpenFolderUri, getPreferredPathMode } from "@/lib/open-folder";
14	import { getPathDisplayModes, type NasConfig } from "@/lib/path-utils";
15	import { toast } from "sonner";
16	import { useState } from "react";
17	
18	interface AssetGridProps {
19	  assets: Asset[];
20	  selectedIds: Set<string>;
21	  onSelect: (id: string, event: React.MouseEvent) => void;
22	  onOpenDetail: (id: string) => void;
23	  isLoading: boolean;
24	}
25	
26	// File type → color hue (oklch hue angle)
27	const FILE_TYPE_HUE: Record<string, number> = {
28	  psd: 260,
29	  ai: 42,
30	  png: 155,
31	  pdf: 20,
32	  jpg: 210,
33	  tif: 295,
34	};
35	const DEFAULT_HUE = 250;
36	
37	// File type → dark badge/tile background color
38	const FILE_TYPE_COLOR: Record<string, string> = {
39	  psd: "oklch(0.42 0.18 260)",
40	  ai:  "oklch(0.62 0.18 42)",
41	  png: "oklch(0.5 0.15 155)",
42	  pdf: "oklch(0.55 0.2 20)",
43	  jpg: "oklch(0.5 0.13 210)",
44	  tif: "oklch(0.5 0.16 295)",
45	};
46	const DEFAULT_COLOR = "oklch(0.55 0.08 250)";
47	
48	function getFileTypeColor(fileType: string): string {
49	  return FILE_TYPE_COLOR[fileType?.toLowerCase()] ?? DEFAULT_COLOR;
50	}
51	
52	function getFileTypeHue(fileType: string): number {
53	  return FILE_TYPE_HUE[fileType?.toLowerCase()] ?? DEFAULT_HUE;
54	}
55	
56	function formatFileSize(bytes: number | null): string | null {
57	  if (bytes == null) return null;
58	  if (bytes < 1024) return `${bytes} B`;
59	  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(0)} KB`;
60	  if (bytes < 1024 * 1024 * 1024) return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
61	  return `${(bytes / (1024 * 1024 * 1024)).toFixed(2)} GB`;
62	}
63	
64	// Glass-style overlay badge
65	function GlassBadge({ children, className }: { children: React.ReactNode; className?: string }) {
66	  return (
67	    <span
68	      className={cn("rounded px-1.5 py-0.5 text-[10px] font-semibold leading-none text-white", className)}
69	      style={{ background: "rgba(0,0,0,0.45)", backdropFilter: "blur(4px)" }}
70	    >
71	      {children}
72	    </span>
73	  );
74	}
75	
76	function useNasConfig(): NasConfig | null {
77	  const { data } = useQuery({
78	    queryKey: ["nas-config"],
79	    queryFn: async () => {
80	      const { data, error } = await supabase
81	        .from("admin_config")
82	        .select("key, value")
83	        .in("key", ["NAS_HOST", "NAS_IP", "NAS_SHARE"]);
84	      if (error) throw error;
85	      const map: Record<string, string> = {};
86	      for (const row of data ?? []) map[row.key] = row.value as string;
87	      if (!map.NAS_HOST || !map.NAS_IP || !map.NAS_SHARE) return null;
88	      return { NAS_HOST: map.NAS_HOST, NAS_IP: map.NAS_IP, NAS_SHARE: map.NAS_SHARE };
89	    },
90	    staleTime: 60_000,
91	  });
92	  return data ?? null;
93	}
94	
95	function AssetCard({
96	  asset,
97	  selected,
98	  onSelect,
99	  onOpenDetail,
100	  nasConfig,
101	}: {
102	  asset: Asset;
103	  selected: boolean;
104	  onSelect: (e: React.MouseEvent) => void;
105	  onOpenDetail: () => void;
106	  nasConfig: NasConfig | null;
107	}) {
108	  const [checkingOut, setCheckingOut] = useState(false);
109	
110	  const fileType = (asset.file_type ?? "").toLowerCase();
111	  const tileColor = getFileTypeColor(fileType);
112	  const hue = getFileTypeHue(fileType);
113	  const hasPreview = !!asset.thumbnail_url;
114	  const licensorPart = asset.licensor_name;
115	  const propertyPart = asset.property_name;
116	  const subtitle = licensorPart && propertyPart
117	    ? `${licensorPart} · ${propertyPart}`
118	    : propertyPart ?? licensorPart ?? null;
119	
120	  async function handleCheckout() {
121	    setCheckingOut(true);
122	    try {
123	      const { data, error } = await supabase.functions.invoke("helper-api/tokens", {
124	        body: { asset_id: asset.id },
125	      });
126	      if (error || !data?.ok) {
127	        toast.error("Could not create checkout link", { description: error?.message ?? data?.error });
128	        return;
129	      }
130	      const uri = `popdam://checkout?token=${encodeURIComponent(data.token)}`;
131	      const a = document.createElement("a");
